            return result.id
        elif field_name == 'score':
            return result.score
        elif field_name == 'text':
            return result.text
        else:
            return result.metadata.get(field_name)

    # Iterate through each search result
    for result in search_results:
        # Extract group value with proper handling for missing fields
        group_value = result.metadata.get(group_by_field)
        if group_value is None or group_value == "":
            group_value = 'unknown'

        group_data = grouped_data[group_value]
        group_data['count'] += 1
        group_data['total_score'] += result.score

        # Update max and min scores
        if result.score > group_data['max_score']:
            group_data['max_score'] = result.score
        if result.score < group_data['min_score']:
            group_data['min_score'] = result.score

        # Apply custom aggregation functions if provided
        if aggregation_funcs:
            for field_name, func in aggregation_funcs.items():
                try:
                    field_value = get_field_value(result, field_name)
                    # Only aggregate if field value is available
                    if field_value is not None:
                        current_stats = group_data['custom_stats'].setdefault(field_name, [])
                        current_stats.append(field_value)
                except Exception as e:
                    # Handle any errors in field extraction or function application
                    continue

    # Prepare final aggregated results
    aggregated_results = {}
    for group_value, group_data in grouped_data.items():
        # Calculate default statistics
        avg_score = group_data['total_score'] / group_data['count'] if group_data['count'] > 0 else 0.0

        # Apply custom aggregation functions to collected values
        custom_stats = {}
        if aggregation_funcs and group_data['custom_stats']:
            for field_name, values in group_data['custom_stats'].items():
                try:
                    custom_stats[field_name] = aggregation_funcs[field_name](values)
                except Exception as e:
                    # Handle any errors during aggregation function execution
                    custom_stats[field_name] = None

        # Combine all statistics
        group_stats = {
            'count': group_data['count'],
            'avg_score': round(avg_score, 4),
            'max_score': group_data['max_score'],
            'min_score': group_data['min_score'],
        }

        # Add custom statistics if available
        group_stats.update(custom_stats)

        aggregated_results[group_value] = group_stats

    return aggregated_results
